Creating a JSON schema for a customer profile involves defining the structure and data types for the information you want to capture about a customer. Below is an example of a JSON schema for a basic customer profile:

```json
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Customer Profile",
  "description": "Schema for a customer profile",
  "type": "object",
  "properties": {
    "customerId": {
      "type": "string",
      "description": "Unique identifier for the customer"
    },
    "firstName": {
      "type": "string",
      "description": "Customer's first name"
    },
    "lastName": {
      "type": "string",
      "description": "Customer's last name"
    },
    "email": {
      "type": "string",
      "format": "email",
      "description": "Customer's email address"
    },
    "phoneNumber": {
      "type": "string",
      "pattern": "^\\+?[0-9\\-\\s]+$",
      "description": "Customer's phone number"
    },
    "address": {
      "type": "object",
      "description": "Customer's address",
      "properties": {
        "street": {
          "type": "string",
          "description": "Street address"
        },
        "city": {
          "type": "string",
          "description": "City"
        },
        "state": {
          "type": "string",
          "description": "State or province"
        },
        "postalCode": {
          "type": "string",
          "description": "Postal or ZIP code"
        },
        "country": {
          "type": "string",
          "description": "Country"
        }
      },
      "required": ["street", "city", "state", "postalCode", "country"]
    },
    "dateOfBirth": {
      "type": "string",
      "format": "date",
      "description": "Customer's date of birth"
    },
    "membershipStatus": {
      "type": "string",
      "enum": ["active", "inactive", "pending"],
      "description": "Customer's membership status"
    }
  },
  "required": ["customerId", "firstName", "lastName", "email"]
}
```

### Explanation:

- **$schema**: Specifies the version of the JSON Schema specification being used.
